        private static readonly Dictionary<string, Spec> ById = BuildIndex();
        public static LevelDefinition Get(LevelCategory category, int number)
        {
            Spec s; if (!ById.TryGetValue(Key(category, number), out s)) throw new ArgumentOutOfRangeException("number");
            LevelDefinition level = new LevelDefinition { id=string.Format("{0}_{1:000}",s.c,s.n), mode=GameMode.MainJourney, generationMode=GenerationMode.ProductionCampaign, category=s.c, levelNumber=s.n, seed=Revision, generationVersion=9, difficultyTier=s.difficulty, width=s.w, height=s.h, parMoves=s.par, moveLimit=s.limit, twoStarMoveTarget=s.two, threeStarMoveTarget=s.three, hardPathLimit=s.hard, archetype=s.archetype, engagementScore=s.engage, strategicDepthScore=s.strategy, catPressureScore=s.pressure, catPuzzleArchetype=s.catArchetype, largeMaze=s.large, tutorialMessage=s.tutorial, designPurpose=s.purpose, intendedStrategy=s.plan, themeId="CozyHome", mechanicSet=s.catX>=0?"CatChaseTurns":"DrawPath", objectiveSet="CleanAllAndDock" };
            DecodeMap(level, s); DecodeRoute(level, s.route);
            if (s.bonusX >= 0) { level.bonusPosition=new GridPosition(s.bonusX,s.bonusY);level.objectives.collectBonus=true;level.objectives.bonusRequiredForThreeStars=s.bonusThree; }
            if (s.catX >= 0) level.cat=new CatDefinition { behavior=CatBehavior.Curious,startPosition=new GridPosition(s.catX,s.catY),horizontalFirst=s.horizontal }; 
            return level;
        }
        public static int Count { get { return Specs.Length; } }
        private static Dictionary<string, Spec> BuildIndex() { var d=new Dictionary<string, Spec>(Specs.Length);for(int i=0;i<Specs.Length;i++)d.Add(Key(Specs[i].c,Specs[i].n),Specs[i]);return d; }
        private static string Key(LevelCategory c,int n) { return ((int)c).ToString()+":"+n.ToString(); }
        private static void DecodeMap(LevelDefinition level, Spec s) { string[] rows=s.map.Split('/');for(int row=0;row<rows.Length;row++){int y=s.h-1-row;for(int x=0;x<s.w;x++){CellContent content;switch(rows[row][x]){case 'S':content=CellContent.Start;break;case 'D':content=CellContent.Dock;break;case 'C':content=CellContent.Crumb;break;case '#':content=CellContent.Wall;break;case 'T':content=CellContent.Toy;break;default:continue;}level.cells.Add(new GridCellDefinition(new GridPosition(x,y),content));}} }
        private static void DecodeRoute(LevelDefinition level,string route) { GridPosition p=level.Find(CellContent.Start);for(int i=0;i<route.Length;i++){Direction d=route[i]=='U'?Direction.Up:route[i]=='R'?Direction.Right:route[i]=='D'?Direction.Down:Direction.Left;level.expectedSolution.Add(new SolutionStep(p,d));p+=DirectionUtility.ToOffset(d);} }
    }
